<div class="gold-header-container">
  <!-- לוגו -->
  <div class="header-logo">
    <i class="pi pi-ticket"></i>
    <span>GOLDEN AUCTION</span>
  </div>

  <!-- תפריט ככפתורים חתיכים -->
  <div class="header-menu">
    <a *ngFor="let item of items" [routerLink]="item.routerLink" class="menu-item">
      <i class="{{item.icon}}"></i>
      <span>{{ item.label }}</span>
    </a>
  </div>
</div>
